import numpy as np
import heapq
from collections import defaultdict

class HuffmanNode:
    def __init__(self, symbol=None, freq=0):
        self.symbol = symbol
        self.freq = freq
        self.left = None
        self.right = None

    def __lt__(self, other):
        return self.freq < other.freq

class HuffmanCoder:
    def __init__(self):
        self.codes = {}
        self.reverse_codes = {}
        self.tree = None

    def build_tree(self, freq_dict):
        """Build Huffman tree from frequency dictionary."""
        heap = [HuffmanNode(sym, freq) for sym, freq in freq_dict.items()]
        heapq.heapify(heap)

        while len(heap) > 1:
            left = heapq.heappop(heap)
            right = heapq.heappop(heap)

            parent = HuffmanNode(freq=left.freq + right.freq)
            parent.left = left
            parent.right = right

            heapq.heappush(heap, parent)

        self.tree = heap[0] if heap else None

    def generate_codes(self, node=None, code=""):
        """Generate codes from tree."""
        if node is None:
            node = self.tree
            self.codes = {}

        if node.symbol is not None:
            self.codes[node.symbol] = code if code else "0"
        else:
            if node.left:
                self.generate_codes(node.left, code + "0")
            if node.right:
                self.generate_codes(node.right, code + "1")

        self.reverse_codes = {v: k for k, v in self.codes.items()}

    def encode(self, text):
        """Encode text to binary string."""
        return ''.join(self.codes[char] for char in text)

    def decode(self, binary_string):
        """Decode binary string to text."""
        result = []
        node = self.tree

        for bit in binary_string:
            if bit == '0':
                node = node.left
            else:
                node = node.right

            if node.symbol is not None:
                result.append(node.symbol)
                node = self.tree

        return ''.join(result)

    def analyze(self, freq_dict):
        """Analyze compression performance."""
        # Calculate entropy
        probs = np.array(list(freq_dict.values()))
        probs = probs[probs > 0]
        entropy = -np.sum(probs * np.log2(probs))

        # Average code length
        avg_length = sum(freq_dict[s] * len(self.codes[s]) for s in freq_dict)

        # Efficiency
        efficiency = entropy / avg_length if avg_length > 0 else 0

        return {
            'entropy': entropy,
            'average_length': avg_length,
            'efficiency': efficiency,
            'redundancy': avg_length - entropy,
            'within_bounds': entropy <= avg_length < entropy + 1
        }

# Test
text = "abracadabra"
freq = {char: text.count(char) / len(text) for char in set(text)}

coder = HuffmanCoder()
coder.build_tree(freq)
coder.generate_codes()

print("Codes:", coder.codes)
encoded = coder.encode(text)
print(f"Original: {text} ({len(text)} chars)")
print(f"Encoded: {encoded} ({len(encoded)} bits)")
decoded = coder.decode(encoded)
print(f"Decoded: {decoded}")
print(f"Correct: {decoded == text}")

print("\nAnalysis:")
analysis = coder.analyze(freq)
for key, val in analysis.items():
    print(f"  {key}: {val}")
